SELECT * FROM ( SELECT rownum rn, TB.* FROM ( SELECT * FROM ( SELECT ESNTL_ID as "uniqId", 'USR01' as "userTy", MBER_ID as "userId", MBER_NM as "userNm", MBER_EMAIL_ADRES as "emailAdres", GROUP_ID as "groupId", MBER_STTUS as "sttus", SBSCRB_DE as "sbscrbDe" FROM TB_GNRL_MBER UNION ALL SELECT ESNTL_ID, 'USR02', ENTRPRS_MBER_ID, CMPNY_NM, APPLCNT_EMAIL_ADRES, GROUP_ID, ENTRPRS_MBER_STTUS, SBSCRB_DE FROM TB_ENTRPRS_MBER UNION ALL SELECT ESNTL_ID, 'USR03', EMPLYR_ID, USER_NM, EMAIL_ADRES, GROUP_ID, EMPLYR_STTUS_CODE, SBSCRB_DE FROM TB_EMPLYR_INFO ) TB WHERE 1=1
AND "sttus" LIKE #{sbscrbSttus}
AND "userTy" = #{userTy}
AND "userId" LIKE #{searchKeyword}
AND "userNm" LIKE '%' ||#{searchKeyword}|| '%'
ORDER BY "sbscrbDe" DESC ) TB ) WHERE rn BETWEEN #{firstIndex} + 1 AND #{firstIndex} + #{recordCountPerPage}

SELECT COUNT(1) totcnt FROM ( SELECT ESNTL_ID as "uniqId", 'USR01' as "userTy", MBER_ID as "userId", MBER_NM as "userNm", MBER_EMAIL_ADRES as "emailAdres", GROUP_ID as "groupId", MBER_STTUS as "sttus", SBSCRB_DE as "sbscrbDe" FROM TB_GNRL_MBER UNION ALL SELECT ESNTL_ID, 'USR02', ENTRPRS_MBER_ID, CMPNY_NM, APPLCNT_EMAIL_ADRES, GROUP_ID, ENTRPRS_MBER_STTUS, SBSCRB_DE FROM TB_ENTRPRS_MBER UNION ALL SELECT ESNTL_ID, 'USR03', EMPLYR_ID, USER_NM, EMAIL_ADRES, GROUP_ID, EMPLYR_STTUS_CODE, SBSCRB_DE FROM TB_EMPLYR_INFO ) TB WHERE 1=1
AND "sttus" LIKE #{sbscrbSttus}
AND "userTy" = #{userTy}
AND "userId" LIKE #{searchKeyword}
AND "userNm" LIKE '%' ||#{searchKeyword}|| '%'

